        elif isinstance(node, ast.ListComp):
            for gen in node.generators:
                if isinstance(gen.target, ast.Name):
                    vars_checked.append(gen.target.id)

    if not vars_checked:
        return True

    for var in vars_checked:
        var_len = len(var)
        if comparison == "should not":
            if var_len > limit:
                return False
        elif comparison == "should":
            if var_len < limit:
                return False
    return True

